    result = main(["--url", "admin", "samples/access.log"])
    assert result == 0


def test_main_with_ip_filter():
    result = main(["--ip", "10.0.0.1", "samples/access.log"])
    assert result == 0


def test_main_with_date_range():
    result = main(
        ["--since", "2026-01-15", "--until", "2026-01-15",
         "samples/access.log"]
    )
    assert result == 0


